  if (!rows.length) {
    msg.statusCode = 401;
    msg.payload = { message: 'Invalid username or password' };
    return [null, msg];
  }

  const localMatches = rows.filter((row) => String(row.username || '').trim() === username);
  const linkedMatches = localMatches.length
    ? []
    : rows.filter((row) => String(row.server_username || '').trim() === username);

  if (localMatches.length > 1 || linkedMatches.length > 1) {
    msg.statusCode = 409;
    msg.payload = { message: 'Multiple accounts match this username. Please contact support.' };
    return [null, msg];
  }

  const user = localMatches[0] || linkedMatches[0];
  if (!user) {
    msg.statusCode = 401;
    msg.payload = { message: 'Invalid username or password' };
    return [null, msg];
  }

  const authMode = user.auth_mode || 'local';
  let passwordValid = false;
  if (authMode === 'server') {
    const serverOfflineVerifier = typeof user.server_offline_verifier === 'string' ? user.server_offline_verifier.trim() : '';
    if (serverOfflineVerifier) {
      passwordValid = bcrypt.compareSync(linkedPasswordValue(password), serverOfflineVerifier);
    } else {
