  } else if (typeof user.password_hash === 'string' && user.password_hash.startsWith('$2')) {
    passwordValid = bcrypt.compareSync(password, user.password_hash);
  } else {
    passwordValid = (user.password_hash === password);
  }
  if (!passwordValid) {
    msg.statusCode = 401;
    msg.payload = { message: 'Invalid username or password' };
    return [null, msg];
  }
  const token = issueSignedToken(user);
  msg.statusCode = 200;
  msg.payload = { token };
  return [null, msg];
}

