function convertHzToKPa(input_frequency) {
    if (typeof input_frequency !== "number" || isNaN(input_frequency)) {
        return null;
    }

    if (input_frequency > 6430) return 0;
    if (input_frequency >= 4330 && input_frequency <= 6430) return 9 - (input_frequency - 4330) * 0.004286;
    if (input_frequency >= 2820 && input_frequency <= 4330) return 15 - (input_frequency - 2820) * 0.003974;
    if (input_frequency >= 1110 && input_frequency <= 2820) return 35 - (input_frequency - 1110) * 0.01170;
    if (input_frequency >= 770 && input_frequency <= 1110) return 55 - (input_frequency - 770) * 0.05884;
    if (input_frequency >= 600 && input_frequency <= 770) return 75 - (input_frequency - 600) * 0.1176;
    if (input_frequency >= 485 && input_frequency <= 600) return 100 - (input_frequency - 485) * 0.2174;
    if (input_frequency >= 293 && input_frequency <= 485) return 200 - (input_frequency - 293) * 0.5208;
    if (input_frequency < 293) return 200;

    return null;
}

function processAndStore(msg) {
    try {
        const data = msg.payload;

        if (!data || !data.deviceInfo || !data.object) {
            node.error("Unexpected payload structure");
            return null;
        }

        // --- NORMALIZE DevEUI
        const rawDevEui = data.deviceInfo.devEui;
        if (!rawDevEui) {
            node.error("Missing devEui in payload");
            return null;
        }
        const devEui = String(rawDevEui).toUpperCase();

        const deviceName = data.deviceInfo.deviceName || "";

        // Prefer ChirpStack timestamp if present
        const timestamp = data.time
            ? new Date(data.time).toISOString()
            : new Date().toISOString();

        // Raw frequencies from KIWI
        const f_wm1 = data.object.input5_frequency;
        const f_wm2 = data.object.input6_frequency;

        // Convert to kPa
        const wm1_kpa = convertHzToKPa(f_wm1);
        const wm2_kpa = convertHzToKPa(f_wm2);

        // Additional measurements
        const light_lux =
            data.object.light_intensity !== undefined
                ? Number(data.object.light_intensity)
                : null;

        const ambient_temperature =
            data.object.ambient_temperature !== undefined
                ? Number(data.object.ambient_temperature)
                : null;

        const relative_humidity =
            data.object.relative_humidity !== undefined
                ? Number(data.object.relative_humidity)
                : null;

        const formattedData = {
            timestamp,
            devEui,        
            deviceName,
            readings: {
                input5_frequency: f_wm1,
                swt_wm1: wm1_kpa,
                input6_frequency: f_wm2,
                swt_wm2: wm2_kpa,
                light_lux: Number.isFinite(light_lux) ? light_lux : null,
                ambient_temperature: Number.isFinite(ambient_temperature) ? ambient_temperature : null,
                relative_humidity: Number.isFinite(relative_humidity) ? relative_humidity : null
            }
        };

        // Node status (compact, readable)
        const statusParts = [];
        if (Number.isFinite(wm1_kpa)) statusParts.push(`WM1 ${wm1_kpa.toFixed(1)} kPa`);
        if (Number.isFinite(wm2_kpa)) statusParts.push(`WM2 ${wm2_kpa.toFixed(1)} kPa`);
        if (Number.isFinite(ambient_temperature)) statusParts.push(`T ${ambient_temperature.toFixed(1)} C`);
        if (Number.isFinite(relative_humidity)) statusParts.push(`RH ${relative_humidity.toFixed(0)} %`);
        if (Number.isFinite(light_lux)) statusParts.push(`Lux ${light_lux.toFixed(0)}`);

        node.status({
            fill: "blue",
            shape: "dot",
            text: statusParts.length ? statusParts.join(" | ") : "no data"
        });

        msg.formattedData = formattedData;
        return msg;

    } catch (err) {
        node.error("Process Data error: " + err.message, msg);
        return null;
    }
}

