// --- GPS decode (Helium mapper style) ---
// We store even if quality is poor; you can filter later by hdop/sats.
function decodeGps(buf) {
  if (!buf || buf.length < 10) {
    return { ok: 0, error: `Payload too short (${buf ? buf.length : 0} bytes)` };
  }

  const lonSign = ((buf[0] >> 7) & 0x01) ? -1 : 1;
  const latSign = ((buf[0] >> 6) & 0x01) ? -1 : 1;

  const encLat = ((buf[0] & 0x3f) << 17) +
                 (buf[1] << 9) +
                 (buf[2] << 1) +
                 (buf[3] >> 7);

  const encLon = ((buf[3] & 0x7f) << 16) +
                 (buf[4] << 8) +
                 buf[5];

  const latitude  = latSign * (encLat * 108 + 53) / 10000000.0;
  const longitude = lonSign * (encLon * 215 + 107) / 10000000.0;
  const altitude_m = ((buf[6] << 8) + buf[7]) - 1000;

  const hdop = buf[8] / 10.0;
  const sats = buf[9];
  const accuracy_m = (hdop * 5 + 5) / 10.0;

  return { ok: 1, latitude, longitude, altitude_m, hdop, sats, accuracy_m };
}

