function computeR2(x,y){
  if(!Array.isArray(x)||!Array.isArray(y)||x.length<3||x.length!==y.length)return null;
  const mx=avg(x),my=avg(y);
  let sxy=0,sxx=0,ssTot=0;
  for(let i=0;i<x.length;i++){
    sxy+=(x[i]-mx)*(y[i]-my);
    sxx+=(x[i]-mx)*(x[i]-mx);
    ssTot+=(y[i]-my)*(y[i]-my);
  }
  if(sxx===0||ssTot===0)return null;
