        twdEpisodeMaxUm=round(Math.max(twdNight,yest?.twd_episode_max_um||0),0);
      }
      let treeStateV5;
      if(qaFlags.lowConfidenceDay){
        treeStateV5=carryForwardState(yest);
      }else{
        treeStateV5=classifyAbsoluteTwd(twdDay!=null?twdDay:0,phenoMod,calibration);
      }
      trees.push({
        deveui:dev.deveui,name:dev.name,is_ref:!!dev.is_ref,quality,validCount,
        d_max_um:dMax,d_min_um:dMin,d_max_time:ex.dMaxTime,d_min_time:ex.dMinTime,mds_um:mds,
        envelope_ref_um:envelopeRef,twd_method:calibration.twd_method,confidence_score:qaFlags.confidenceScore,
        qa_flags_json:JSON.stringify(qaFlags),low_confidence_day:qaFlags.lowConfidenceDay?1:0,tree_state_v5:treeStateV5,
        d_max_running_um:envelopeRef,twd_night_um:twdNight,twd_day_um:twdDay,
        twd_norm_night:twdNormNight,twd_norm_day:twdNormDay,mds_norm:mdsNorm,
        tgr_um:tgr,tgr_smoothed_um:tgrSmoothed,delta_twd_smoothed:deltaTwdSmoothed,
        dr_um:dr,recovery_delta_um:rDelta5day,r_delta_5day:rDelta5day,recovery_ratio:recoveryRatio,recovery_ratio_smoothed:recoveryRatioSmoothed,
        twd_um:twdNight,signal_intensity:null,stress:treeStateV5,
        twd_episode_active:twdEpisodeActive,twd_episode_start:twdEpisodeStart,twd_episode_max_um:twdEpisodeMaxUm,
