    }

    const ref=trees.find(t=>t.is_ref&&t.mds_um!=null&&t.mds_um>0);
    for(const t of trees){
      if(ref&&!t.is_ref&&t.mds_um!=null)t.signal_intensity=round(t.mds_um/ref.mds_um,2);
    }

    const aggregation=aggregateZoneStress(trees.filter(t=>!t.is_ref));
    const nonRef=aggregation.usableTrees;
    const zoneSt=aggregation.zoneStress;

    const pastR=await q(`SELECT zone_stress_summary FROM zone_daily_recommendations WHERE zone_id=${zone.zone_id} AND date<'${ANALYTICS_DATE}' ORDER BY date DESC LIMIT 2`);
    const hist3=[zoneSt,...pastR.map(r=>r.zone_stress_summary)].slice(0,3);

    if(zs.recovery_verification_active){
      const dl=new Date(zs.recovery_verification_deadline);
      const recoveryThreshold=(calibration.thresholds.mild||CALIBRATIONS.default.thresholds.mild)*(phenoMod>0?phenoMod:1.0);
      const verifiableTrees=nonRef.filter(t=>!t.low_confidence_day&&t.twd_night_um!=null);
      const passed=verifiableTrees.length>0&&verifiableTrees.every(t=>t.twd_night_um<recoveryThreshold&&(t.recovery_ratio_smoothed==null||t.recovery_ratio_smoothed>0.8));
      if(passed){
        zs.recovery_verification_active=0;
        node.log('Zone '+zone.zone_name+': recovery verification PASSED');
      }else if(NOW>dl){
        zs.recovery_verification_deadline=new Date(dl.getTime()+3*86400000).toISOString();
        node.warn('Zone '+zone.zone_name+': slow_recovery — extending 3 days');
      }
    }

    const prevSt=pastR[0]?.zone_stress_summary||'none';
    if(zoneSt!=='unknown'&&(prevSt==='significant'||prevSt==='severe')&&(RANK[zoneSt]||0)<(RANK[prevSt]||0)&&!zs.recovery_verification_active){
      const pc=await q(`SELECT COUNT(*) AS c FROM zone_daily_recommendations WHERE zone_id=${zone.zone_id} AND zone_stress_summary IN ('significant','severe') AND date>=date('${ANALYTICS_DATE}','-3 days') AND date<'${ANALYTICS_DATE}'`);
      if((pc[0]?.c||0)>=3){
        zs.recovery_verification_active=1;
        zs.recovery_verification_start=COMPUTED_AT;
        zs.recovery_verification_deadline=new Date(NOW.getTime()+5*86400000).toISOString();
        node.log('Zone '+zone.zone_name+': entering recovery verification');
      }
    }

    const schedule=(await q(`SELECT trigger_metric,threshold_kpa,duration_minutes,enabled FROM irrigation_schedules WHERE irrigation_zone_id=${zone.zone_id} LIMIT 1`))[0]||null;
    const rawDecision=irrDecision(hist3,rain,zs,nonRef);
    const finalDecision=applyDendroSchedulePolicy(rawDecision,hist3,schedule);
    const {action,reasoning}=finalDecision;
    const incActions=['increase_10','increase_20','emergency_irrigate'];
    if(incActions.includes(action)){
      zs.consecutive_increases=(zs.consecutive_increases||0)+1;
      if(zs.consecutive_increases>5)node.warn('Zone '+zone.zone_name+': '+zs.consecutive_increases+' consecutive increases — manual review recommended');
    }else{
      zs.consecutive_increases=0;
    }

