    }

    const recJson=JSON.stringify({
      zone_id:String(zone.zone_id),
      date:ANALYTICS_DATE,
      trees:trees.map(t=>({
        device_eui:t.deveui,
        name:t.name,
        is_reference:t.is_ref,
        twd_night_um:t.twd_night_um,
        twd_day_um:t.twd_day_um,
        twd_norm_night:t.twd_norm_night,
        mds_norm:t.mds_norm,
        recovery_ratio_smoothed:t.recovery_ratio_smoothed,
