  msg.payload={success:true,date:payloadDate,zones:summary};
  await close();
  return msg;
}catch(err){
  node.error('Analytics v5: '+err.message+'\n'+err.stack);
  node.status({fill:'red',shape:'ring',text:err.message});
  try{await close();}catch(e){}
  return null;
}
})();

